11: // Validator is responsible for the Validation stage of the plugin loader pipeline.
12: type Validator interface {
13: 	Validate(ctx context.Context, ps *plugins.Plugin) error
14: }
15: 
16: // ValidateFunc is the function used for the Validate step of the Validation stage.
17: type ValidateFunc func(ctx context.Context, p *plugins.Plugin) error
18: 
19: type Validate struct {
20: 	cfg           *config.PluginManagementCfg
21: 	validateSteps []ValidateFunc
22: 	log           log.Logger
23: }
24: 
25: type Opts struct {
26: 	ValidateFuncs []ValidateFunc
27: }
28: 
29: // New returns a new Validation stage.
30: func New(cfg *config.PluginManagementCfg, opts Opts) *Validate {
31: 	if opts.ValidateFuncs == nil {
32: 		opts.ValidateFuncs = DefaultValidateFuncs(cfg)
33: 	}
34: 
35: 	return &Validate{
36: 		cfg:           cfg,
37: 		validateSteps: opts.ValidateFuncs,
38: 		log:           log.New("plugins.validation"),
39: 	}
40: }
41: 
42: // Validate will execute the Validate steps of the Validation stage.
43: func (v *Validate) Validate(ctx context.Context, ps *plugins.Plugin) error {
44: 	if len(v.validateSteps) == 0 {
45: 		return nil
46: 	}
47: 
48: 	for _, validate := range v.validateSteps {
49: 		err := validate(ctx, ps)
50: 		if err != nil {
51: 			v.log.Error("Plugin validation failed", "pluginId", ps.ID, "error", err)
52: 			return err
53: 		}
54: 	}
55: 
56: 	return nil
57: }
