172: func (s *LocalSource) readPluginJSON(pluginJSONPath string) (plugins.JSONData, error) {
173: 	reader, err := s.readFile(pluginJSONPath)
174: 	defer func() {
175: 		if reader == nil {
176: 			return
177: 		}
178: 		if err = reader.Close(); err != nil {
179: 			s.log.Warn("Failed to close plugin JSON file", "path", pluginJSONPath, "error", err)
180: 		}
181: 	}()
182: 	if err != nil {
183: 		s.log.Warn("Skipping plugin loading as its plugin.json could not be read", "path", pluginJSONPath, "error", err)
184: 		return plugins.JSONData{}, err
185: 	}
186: 	plugin, err := plugins.ReadPluginJSON(reader)
187: 	if err != nil {
188: 		s.log.Warn("Skipping plugin loading as its plugin.json could not be read", "path", pluginJSONPath, "error", err)
189: 		return plugins.JSONData{}, err
190: 	}
191: 
192: 	return plugin, nil
193: }
