240: func (s *LocalSource) readFile(pluginJSONPath string) (io.ReadCloser, error) {
241: 	s.log.Debug("Loading plugin", "path", pluginJSONPath)
242: 
243: 	if !strings.EqualFold(filepath.Ext(pluginJSONPath), ".json") {
244: 		return nil, ErrInvalidPluginJSONFilePath
245: 	}
246: 
247: 	absPluginJSONPath, err := filepath.Abs(pluginJSONPath)
248: 	if err != nil {
249: 		return nil, err
250: 	}
251: 
252: 	// Wrapping in filepath.Clean to properly handle
253: 	// gosec G304 Potential file inclusion via variable rule.
254: 	return os.Open(filepath.Clean(absPluginJSONPath))
255: }
