30: func DefaultDecorateFuncs(cfg *config.PluginManagementCfg) []DecorateFunc {
31: 	return []DecorateFunc{
32: 		AppDefaultNavURLDecorateFunc,
33: 		TemplateDecorateFunc,
34: 		AppChildDecorateFunc(),
35: 		SkipHostEnvVarsDecorateFunc(cfg),
36: 	}
